text:
@import '../../style/themes/index';
@import '../../style/mixins/index';
@import '../../style/core/motion/zoom';

@tooltip-prefix-cls: ~'@{ant-prefix}-tooltip';

// Base class
.@{tooltip-prefix-cls} {
  .reset-component();

  --antd-arrow-background-color: @tooltip-bg;

  position: absolute;
  z-index: @zindex-tooltip;
  display: block;
  width: max-content;
  max-width: @tooltip-max-width;
  visibility: visible;

  &-content {
    position: relative;
  }

  &-hidden {
    display: none;
  }

  // Wrapper for the tooltip content
  &-inner {
    min-width: 30px;
    min-height: 32px;
    padding: calc(@padding-sm / 2) @padding-xs;
    color: @tooltip-color;
    text-align: start;
    text-decoration: none;
    word-wrap: break-word;
    background-color: @tooltip-bg;
    border-radius: @border-radius-base;
    box-shadow: @box-shadow-base;
  }

  // Arrow Style
  .placementArrow(@tooltip-arrow-width, 4px, @arrow-border-radius, var(--antd-arrow-background-color), @popover-arrow-box-shadow);
}

.generator-tooltip-preset-color(@i: length(@preset-colors)) when (@i > 0) {
  .generator-tooltip-preset-color(@i - 1);
  @color: extract(@preset-colors, @i);
  @lightColor: '@{color}-6';

  .@{tooltip-prefix-cls}-@{color} {
    .@{tooltip-prefix-cls}-inner {
      background-color: @@lightColor;
    }

    .@{tooltip-prefix-cls}-arrow {
      --antd-arrow-background-color: @@lightColor;
    }
  }
}

.generator-tooltip-preset-color();

// Animations
.zoom-motion('zoom-big-fast', antZoomBig, @animation-duration-fast);

@import './rtl';

@import '../../style/themes/index';

@tree-prefix-cls: ~'@{ant-prefix}-tree';

.@{tree-prefix-cls}.@{tree-prefix-cls}-directory {
  // ================== TreeNode ==================
  .@{tree-prefix-cls}-treenode {
    position: relative;

    // Hover color
    &::before {
      position: absolute;
      top: 0;
      right: 0;
      bottom: 4px;
      left: 0;
      transition: background-color 0.3s;
      content: '';
      pointer-events: none;
    }

    &:hover {
      &::before {
        background: @item-hover-bg;
      }
    }

    // Elements
    > * {
      z-index: 1;
    }

    // >>> Switcher
    .@{tree-prefix-cls}-switcher {
      transition: color 0.3s;
    }

    // >>> Title
    .@{tree-prefix-cls}-node-content-wrapper {
      border-radius: 0;
      user-select: none;

      &:hover {
        background: transparent;
      }

      &.@{tree-prefix-cls}-node-selected {
        color: @tree-directory-selected-color;
        background: transparent;
      }
    }

    // ============= Selected =============
    &-selected {
      &:hover::before,
      &::before {
        background: @tree-directory-selected-bg;
      }

      // >>> Switcher
      .@{tree-prefix-cls}-switcher {
        color: @tree-directory-selected-color;
      }

      // >>> Title
      .@{tree-prefix-cls}-node-content-wrapper {
        color: @tree-directory-selected-color;
        background: transparent;
      }
    }
  }
}

@tabs-prefix-cls: rc-tabs;

.@{tabs-prefix-cls} {
  display: flex;

  // ========================== Vertical ==========================
  &-top,
  &-bottom {
    flex-direction: column;

    .@{tabs-prefix-cls}-ink-bar {
      height: 3px;
    }
  }

  &-top {
    .@{tabs-prefix-cls}-ink-bar {
      bottom: 0;
    }
  }

  &-bottom {
    .@{tabs-prefix-cls}-nav {
      order: 1;
    }

    .@{tabs-prefix-cls}-content {
      order: 0;
    }

    .@{tabs-prefix-cls}-ink-bar {
      top: 0;
    }
  }

  // ========================= Horizontal =========================
  &-left,
  &-right {
    &.@{tabs-prefix-cls}-editable .@{tabs-prefix-cls}-tab {
      padding-right: 32px;
    }

    .@{tabs-prefix-cls}-nav-wrap {
      flex-direction: column;
    }

    .@{tabs-prefix-cls}-ink-bar {
      width: 3px;
    }

    .@{tabs-prefix-cls}-nav {
      flex-direction: column;
      min-width: 50px;

      &-list,
      &-operations {
        flex: 1 0 auto; // fix safari scroll problem
        flex-direction: column;
      }
    }
  }

  &-left {
    .@{tabs-prefix-cls}-ink-bar {
      right: 0;
    }
  }

  &-right {
    .@{tabs-prefix-cls}-nav {
      order: 1;
    }

    .@{tabs-prefix-cls}-content {
      order: 0;
    }

    .@{tabs-prefix-cls}-ink-bar {
      left: 0;
    }
  }
}

@import (reference) "../style/themes/default.less";

.am-filter {
  &-show {
    height: 100vh;
    display: block;
    position: relative;
  }

  &-hide {
    display: none;
  }

  &-mask, &-document {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
  }

  &-mask {
    bottom: 0;
    background: @color-product-mask;
    background: var(--am-filter-mask, @color-product-mask);
  }

  &-content {
    background: @color-fill-grey-inverse;
    background: var(--am-filter-content-bgc, @color-fill-grey-inverse);
    display: flex;
    flex-direction: column;
    overflow-x: hidden;
    overflow-y: scroll;
  }

  &-list {
    flex: 1;
    padding-left: @size-3;
    padding-left: var(--am-filter-padding, @size-3);
    padding-bottom: @size-3;
    padding-bottom: var(--am-filter-padding, @size-3);
    overflow-x: hidden;
    overflow-y: scroll;
    max-height: 830 * @pixelSize;
    box-sizing: border-box;
  }

  &-btn {
    width: 100%;
    display: flex;
  }

  &-default, &-primary {
    flex: 1;
    height: @size-12;
    height: var(--am-filter-button-height, @size-12);
    font-size: @font-size-title;
    font-size: var(--am-filter-button-fontSize, @font-size-title);
    box-sizing: border-box;
    width: 50%;
    border: 0;
    border-radius: 0;
  }

  &-default {
    border-top: @border-width-standard solid #eee;
    border-right: none;
  }

  &-child-2 {
    & > .am-filter-item-wrap {
      width: 50%;
    }
  }

  &-child-3 {
    & > .am-filter-item-wrap {
      width: 33.3%;
    }
  }
}

// Amaze UI for legacy browsers
//
// =============================================================================

// button-group.less
// Justify button group
// =============================================================================

// Justify button group
.hook-button-group-justify() {
  .lte9 & {
    display: table;
    table-layout: fixed;
    border-collapse: separate;

    > .@{ns}btn,
    > .@{ns}btn-group {
      float: none;
      display: table-cell;
      width: 1%;
    }
  }
}

// Justify nav
.hook-nav-justify() {
  .lte9 & {
    & > li {
      display: table-cell;
      width: 1%;
    }
  }
}

// JS Progress
.lte9 {
  // no CSS animation，hide spinner
  #nprogress {
    .nprogress-spinner {
      display: none !important;
    }
  }
}

.lte8 {
  .@{ns}dimmer {
    background-color: #000;
    filter: ~"alpha(opacity=60)";
  }

  .@{ns}modal-actions {
    display: none;

    &.@{ns}modal-active {
      display: block;
    }
  }

  // Plugin OffCanvas rgba() bg
  .@{ns}﻿offcanvas.@{ns}active {
    background: #000;
  }

  // Plugin Popover: caret style
  .@{ns}popover .@{ns}popover-caret {
    border: 8px solid transparent;
  }

  .@{ns}popover-top .@{ns}popover-caret {
    border-top: 8px solid @popover-bg;
    border-bottom: none;
  }

  .@{ns}popover-left .@{ns}popover-caret {
    right: -8px;
    margin-top: -6px;
    border-left: 8px solid @popover-bg;
    border-right: none;
  }

  .@{ns}popover-right .@{ns}popover-caret {
    left: -8px;
    margin-top: -6px;
    border-right: 8px solid @popover-bg;
    border-left: none;
  }
}

@class-prefix-modal: ~'adm-modal';

.@{class-prefix-modal} {
  --z-index: var(--adm-modal-z-index, 1000);

  ---z-index: var(--z-index);
  .adm-center-popup {
    --z-index: var(---z-index);
  }
}

.@{class-prefix-modal}-body {
  width: 100%;
  max-height: 70vh;
  font-size: var(--adm-font-size-6);
  overflow: hidden;

  display: flex;
  flex-direction: column;
  > * {
    flex: none;
  }
  > .adm-modal-content {
    flex: auto;
  }

  &:not(.adm-modal-with-image) {
    padding-top: 20px;
  }
}

.adm-modal-image-container {
  margin-bottom: 12px;
  max-height: 40vh;
  overflow-y: scroll;
}
.adm-modal-header {
  margin-bottom: 8px;
  padding: 0 12px;
}
.adm-modal-title {
  margin-bottom: 8px;
  padding: 0 12px;
  font-weight: bold;
  font-size: var(--adm-font-size-10);
  line-height: 25px;
  text-align: center;
}
.adm-modal-content {
  padding: 0 12px 12px;
  max-height: 70vh;
  overflow-x: hidden;
  overflow-y: auto;
  font-size: var(--adm-font-size-7);
  line-height: 1.4;
  color: var(--adm-color-text);
}

.adm-modal-footer {
  user-select: none;
  padding: 8px 12px 12px;
  &-empty {
    padding: 0;
    height: 8px;
  }
  &.adm-space {
    --gap-vertical: 20px;
  }
  .adm-modal-button {
    font-size: var(--adm-font-size-10);
    line-height: 25px;
    &:not(.adm-modal-button-primary) {
      padding-top: 0;
      padding-bottom: 0;
      &::before {
        display: none;
      }
      &:active {
        opacity: 0.7;
      }
    }
  }
}

@class-prefix-popover: ~'adm-popover';

.@{class-prefix-popover} {
  --z-index: var(--adm-popover-z-index, 1030);

  --background: #ffffff;
  --arrow-size: 8px;
  --content-padding: 8px 12px;

  &&-dark {
    --background: rgba(0, 0, 0, 0.75);
    --adm-color-text: #ffffff;
    color: #ffffff;
    .adm-popover-inner {
      box-shadow: none;
    }
  }

  color: var(--adm-color-text);
  position: absolute;
  top: 0;
  left: 0;
  z-index: var(--z-index);
  white-space: normal;
  text-align: left;
  cursor: auto;
  user-select: text;
  animation: none;

  &::after {
    position: absolute;
    background: fade(#ffffff, 1%);
    content: '';
  }
  &-hidden {
    display: none;
  }

  &-inner {
    background-color: var(--background);
    background-clip: padding-box;
    border-radius: 8px;
    box-shadow: 0 0 30px 0 rgba(51, 51, 51, 0.2);
    font-size: var(--adm-font-size-7);
    width: max-content;
    min-width: 32px;
    max-width: calc(100vw - 24px);
    overflow-y: hidden;
    &-content {
      padding: var(--content-padding);
    }
  }

  &-arrow {
    position: absolute;
    display: block;
    height: var(--arrow-size);
    width: var(--arrow-size);
    overflow: visible;
    background: transparent;
  }

  &-arrow-icon {
    display: block;
    height: var(--arrow-size);
    width: calc(var(--arrow-size) / 8 * 15);
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%) rotate(var(--arrow-icon-rotate));
  }

  .adm-popover-arrow {
    color: var(--background);
  }
}

@class-prefix-picker: ~'adm-picker';

.@{class-prefix-picker} {
  --header-button-font-size: var(--adm-font-size-7);
  --title-font-size: var(--adm-font-size-7);
  --item-font-size: var(--adm-font-size-8);
  --item-height: 34px;

  width: 100%;
  height: 300px;
  overflow: hidden;
  position: relative;
  display: flex;
  flex-direction: column;

  ---item-font-size: var(--item-font-size);
  ---item-height: var(--item-height);
  .adm-picker-view.adm-picker-view {
    --item-font-size: var(---item-font-size);
    --item-height: var(---item-height);
  }
}

.@{class-prefix-picker}-header {
  flex-shrink: 0;
  border-bottom: solid 1px var(--adm-color-border);
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 4px 4px;
  &-button {
    font-size: var(--header-button-font-size);
    display: inline-block;
    padding: 8px 8px;
    &-disabled {
      &,
      &:active {
        opacity: 0.4;
        cursor: not-allowed;
      }
    }
  }
  &-title {
    padding: 4px 4px;
    font-size: var(--title-font-size);
    color: var(--adm-color-text);
    text-align: center;
    flex: 1;
  }
}

.@{class-prefix-picker}-body {
  flex: 1;
  width: 100%;
  height: 100%;

  > .adm-picker-view {
    --height: 100%;
  }
}

.@{class-prefix-picker}-popup {
  & .adm-popup-body {
    border-top-left-radius: 8px;
    border-top-right-radius: 8px;
  }
}

@class-prefix-space: ~'adm-space';

.@{class-prefix-space}-item {
  flex: none;
}

.@{class-prefix-space} {
  display: inline-flex;
  --gap: 8px;
  --gap-vertical: var(--gap);
  --gap-horizontal: var(--gap);
  &-vertical {
    flex-direction: column;
    > .@{class-prefix-space}-item {
      margin-bottom: var(--gap-vertical);
      &:last-child {
        margin-bottom: 0;
      }
    }
  }
  &-horizontal {
    flex-direction: row;
    > .@{class-prefix-space}-item {
      margin-right: var(--gap-horizontal);
      &:last-child {
        margin-right: 0;
      }
    }
    &.@{class-prefix-space}-wrap {
      flex-wrap: wrap;
      margin-bottom: calc(var(--gap-vertical) * -1);
      > .@{class-prefix-space}-item {
        padding-bottom: var(--gap-vertical);
      }
    }
  }
  &.@{class-prefix-space}-block {
    display: flex;
  }
  &-align {
    &-center {
      align-items: center;
    }
    &-start {
      align-items: flex-start;
    }
    &-end {
      align-items: flex-end;
    }
    &-baseline {
      align-items: baseline;
    }
  }
  &-justify {
    &-center {
      justify-content: center;
    }
    &-start {
      justify-content: flex-start;
    }
    &-end {
      justify-content: flex-end;
    }
    &-between {
      justify-content: space-between;
    }
    &-around {
      justify-content: space-around;
    }
    &-evenly {
      justify-content: space-evenly;
    }
    &-stretch {
      justify-content: stretch;
    }
  }
}

@import '~antd/es/style/themes/default.less';
@import '../BasicLayout.less';

@top-nav-header-prefix-cls: ~'@{ant-prefix}-pro-top-nav-header';

.@{top-nav-header-prefix-cls} {
  position: relative;
  width: 100%;
  height: 100%;
  box-shadow: 0 1px 4px 0 rgba(0, 21, 41, 0.12);
  transition: background 0.3s, width 0.2s;

  :global {
    .ant-menu.ant-menu-dark .ant-menu-item-selected,
    .ant-menu-submenu-popup.ant-menu-dark .ant-menu-item-selected {
      background: #252a3d;
    }
  }

  .@{ant-prefix}-menu-submenu.@{ant-prefix}-menu-submenu-horizontal {
    height: 100%;
    .@{ant-prefix}-menu-submenu-title {
      height: 100%;
    }
  }

  &.light {
    background-color: @component-background;
    .@{top-nav-header-prefix-cls}-logo {
      h1 {
        color: @primary-color;
      }
    }
    .anticon {
      color: inherit;
    }
  }

  &-main {
    display: flex;
    height: 100%;
    padding-left: 16px;
    &-left {
      display: flex;
      min-width: 192px;
    }
  }

  .anticon {
    color: @btn-primary-color;
  }

  &-logo {
    position: relative;
    min-width: 165px;
    height: 100%;
    overflow: hidden;
    transition: all 0.3s;
    img {
      display: inline-block;
      height: 32px;
      vertical-align: middle;
    }
    h1 {
      display: inline-block;
      margin: 0 0 0 12px;
      color: @btn-primary-color;
      font-weight: 400;
      font-size: 16px;
      vertical-align: top;
    }
  }
  &-menu {
    min-width: 0;
    .@{ant-prefix}-menu.@{ant-prefix}-menu-horizontal {
      height: 100%;
      border: none;
    }
  }
}

//
// Grid system
// --------------------------------------------------


// Container widths
//
// Set the container width, and override it for fixed navbars in media queries.

.container {
  .container-fixed();

  @media (min-width: @screen-sm-min) {
    width: @container-sm;
  }
  @media (min-width: @screen-md-min) {
    width: @container-md;
  }
  @media (min-width: @screen-lg-min) {
    width: @container-lg;
  }
}


// Fluid container
//
// Utilizes the mixin meant for fixed width containers, but without any defined
// width for fluid, full width layouts.

.container-fluid {
  .container-fixed();
}


// Row
//
// Rows contain and clear the floats of your columns.

.row {
  .make-row();
}

.row-no-gutters {
  margin-right: 0;
  margin-left: 0;

  [class*="col-"] {
    padding-right: 0;
    padding-left: 0;
  }
}


// Columns
//
// Common styles for small and large grid columns

.make-grid-columns();


// Extra small grid
//
// Columns, offsets, pushes, and pulls for extra small devices like
// smartphones.

.make-grid(xs);


// Small grid
//
// Columns, offsets, pushes, and pulls for the small device range, from phones
// to tablets.

@media (min-width: @screen-sm-min) {
  .make-grid(sm);
}


// Medium grid
//
// Columns, offsets, pushes, and pulls for the desktop device range.

@media (min-width: @screen-md-min) {
  .make-grid(md);
}


// Large grid
//
// Columns, offsets, pushes, and pulls for the large desktop device range.

@media (min-width: @screen-lg-min) {
  .make-grid(lg);
}

// Cascader
// --------------------------------------------------
@prefix-cls-carousel: e("@{prefix-cls}-carousel");


.@{prefix-cls-carousel} {
  position: relative;
  overflow: hidden;

  &-content {
    position: relative;

    height: 100%;
  }
  &-indicators {
    position: absolute;
    bottom: 0;
    z-index: 99;

    padding: 1rem;
  }
  &-center {
    left: 50%;

    transform: translateX(-50%);
  }
  &-left {
    left: 0;
  }
  &-right {
    right: 0;
  }
  &-indicator-icon {
    border: 1px solid rgba(255, 255, 255, .6);
    width: 9px;
    height: 9px;
    display: inline-block;
    border-radius: 50%;
    margin: 0 5px;
    cursor: pointer;
  }
  .carousel-indicator-active {
    background: #cfcccc;
    border-color: #cfcccc;
    opacity: 0.6;
  }
  &-btn {
    position: absolute;
    top: 50%;
    z-index: 99;

    transform: translateY(-50%);
    cursor: pointer;
    background-color: #000;
    transition: opacity .3s;
    opacity: .3;
  }
  &-btn:hover {
    opacity: .5;
  }
  &-left-btn {
    left: 0;

    padding: 1rem .5rem .75rem .8rem;
  }
  &-right-btn {
    right: 0;

    padding: 1rem .8rem .75rem .5rem;
  }
  &-icon {
    display: inline-block;
    width: 20px;
    height: 20px;
    border-left: 2px solid #fff;
    border-bottom: 2px solid #fff;
  }
  &-icon-left {
    transform: rotate(45deg);
  }
  &-icon-right {
    transform: rotate(-135deg);
  }
  &-item {
    float: left;
    width: 100%;
    height: 100%;
    text-align: center;
    > a, img , > a > img {
      // max-width: 100%;
    }
  }
}

//
// Jumbotron
// --------------------------------------------------
@jumbotron-padding:              30px;
@jumbotron-color:                inherit;
@jumbotron-bg:                   #666;
@jumbotron-heading-color:        inherit;
@jumbotron-font-size:            14px;
@jumbotron-heading-font-size:    28px;

.jumbotron {
  padding-top: @jumbotron-padding;
  padding-bottom: @jumbotron-padding;
  margin-bottom: @jumbotron-padding;
  color: @jumbotron-color;
  background-color: @jumbotron-bg;

  h1,
  .h1 {
    color: @jumbotron-heading-color;
  }

  p {
    margin-bottom: (@jumbotron-padding / 2);
    font-size: @jumbotron-font-size;
    font-weight: 200;
  }

  > hr {
    border-top-color: darken(@jumbotron-bg, 10%);
  }

  .container &,
  .container-fluid & {
    border-radius: @border-radius-large; // Only round corners at higher resolutions if contained in a container
    padding-left: (@grid-gutter-width / 2);
    padding-right: (@grid-gutter-width / 2);
  }

  .container {
    max-width: 100%;
  }

  @media screen and (min-width: @screen-sm-min) {
    padding-top: (@jumbotron-padding * 1.6);
    padding-bottom: (@jumbotron-padding * 1.6);

    .container &,
    .container-fluid & {
      padding-left: (@jumbotron-padding * 2);
      padding-right: (@jumbotron-padding * 2);
    }

    h1,
    .h1 {
      font-size: @jumbotron-heading-font-size;
    }
  }
}

@class-prefix-dialog: ~'adm-dialog';

.@{class-prefix-dialog} {
  --z-index: var(--adm-dialog-z-index, 1000);

  ---z-index: var(--z-index);
  .adm-center-popup {
    --z-index: var(---z-index);
  }
}

.@{class-prefix-dialog}-body {
  width: 100%;
  max-height: 70vh;
  font-size: var(--adm-font-size-6);
  overflow: hidden;

  display: flex;
  flex-direction: column;
  > * {
    flex: none;
  }
  > .adm-dialog-content {
    flex: auto;
  }

  &:not(.adm-dialog-with-image) {
    padding-top: 20px;
  }
}

.adm-dialog-image-container {
  margin-bottom: 12px;
  max-height: 40vh;
}
.adm-dialog-header {
  margin-bottom: 8px;
  padding: 0 12px;
}
.adm-dialog-title {
  margin-bottom: 8px;
  padding: 0 12px;
  font-weight: bold;
