      .@{css-prefix}button + .@{css-prefix}button {
        @apply ml-4;
      }
    }
  }

  .tiny-grid__body-wrapper {
    @apply border-b-0;
  }

  .tiny-grid.tiny-grid__border:after {
    @apply border-color-bg-3;
  }

  .tiny-split-trigger-con-vertical.tiny-split-trigger-con-simple {
    @apply ~'pl-0.5';
    @apply ~'pr-0.5';
  }

  .tiny-split-trigger-vertical {
    @apply border-color-border;
  }

  .tiny-split-wrapper {
    box-shadow: none;
  }

  &.radio-check {
    .tiny-split-trigger-con-vertical.tiny-split-trigger-con-simple {
      @apply hidden;
    }

    .tiny-dialog-select__body-tree {
      @apply mr-0;
    }
  }
}

@class-prefix-form-item: ~'adm-form-item';

.@{class-prefix-form-item} {
  + .@{class-prefix-form-item} {
    border-top: none;
  }

  &-label {
    display: block;
    height: 100%;
    line-height: 1.5;
    box-sizing: border-box;
    position: relative;
    color: var(--adm-color-text-secondary);

    .adm-form-item-required-asterisk {
      position: absolute;
      left: -0.6em;
      top: 0;
      font-family: SimSun, sans-serif;
      color: var(--adm-color-danger);
      user-select: none;
    }
    .adm-form-item-required-text {
      margin-left: 4px;
      color: var(--adm-color-weak);
    }

    &-help {
      margin-left: 4px;
      cursor: pointer;
    }
  }

  &-child {
    display: flex;
    &-position-normal {
      justify-content: normal;
      > * {
        flex: auto;
      }
    }
    &-position-right {
      justify-content: flex-end;
      > * {
        flex: none;
      }
    }
  }

  &-feedback-error {
    color: var(--adm-color-danger);
    margin-top: 4px;
  }
  &-feedback-warning {
    color: var(--adm-color-warning);
    margin-top: 4px;
  }

  &&-hidden {
    display: none;
  }

  &&-horizontal {
    &.adm-list-item {
      --align-items: stretch;
    }
    .adm-list-item-content-prefix {
      padding-top: 12px;
      padding-bottom: 12px;
    }
    .adm-list-item-content-extra {
      align-self: center;
    }
  }

  &&-vertical {
    .adm-form-item-label {
      font-size: var(--adm-font-size-7);
      margin-bottom: 4px;
    }
  }
}

